def get_shell() -> str:
    """Get shell name."""
    return os.environ.get("SHELL", "").lower() or DEFAULT_SHELL


def get_shell_exe() -> str:
    """Get shell executable."""
    shell_info = get_shell_info(get_shell())
    return shell_info.get("exe", DEFAULT_SHELL_EXE)


def get_shell_base() -> str:
    """Get shell base."""
    shell_info = get_shell_info(get_shell())
